"""IAM credentials management for GreenNode AgentBase Identity SDK.

Provides IAMCredentials class for managing client ID and client secret
with support for multiple credential sources (constructor, environment variables, config file).
"""

import json
import os
from pathlib import Path
from typing import Optional

from ..exceptions import GreenNodeConfigurationError
from ..core.config import get_config_value


class IAMCredentials:
    """Manages IAM credentials (client ID and client secret).

    Supports multiple credential sources with the following priority order:
    1. Constructor parameters
    2. Environment variables (GREENNODE_CLIENT_ID, GREENNODE_CLIENT_SECRET)
    3. Config file (.greennode.json in current directory)

    Args:
        client_id: Optional client ID (if not provided, will try env vars and config file)
        client_secret: Optional client secret (if not provided, will try env vars and config file)

    Example:
        >>> # From constructor
        >>> creds = IAMCredentials(client_id="key", client_secret="secret")
        >>> # From environment variables
        >>> # Set GREENNODE_CLIENT_ID and GREENNODE_CLIENT_SECRET
        >>> creds = IAMCredentials()
        >>> # From config file
        >>> # Create .greennode.json with {"client_id": "...", "client_secret": "..."}
        >>> creds = IAMCredentials()
    """

    def __init__(
        self,
        client_id: Optional[str] = None,
        client_secret: Optional[str] = None,
    ) -> None:
        """Initialize IAM credentials from multiple sources."""
        self._client_id: Optional[str] = client_id
        self._client_secret: Optional[str] = client_secret

        # Try environment variables and config file if not provided
        # Use centralized config utility for consistency
        if self._client_id is None:
            self._client_id = get_config_value("GREENNODE_CLIENT_ID")
        if self._client_secret is None:
            self._client_secret = get_config_value("GREENNODE_CLIENT_SECRET")

        # Fallback to direct config file loading (client_id/client_secret keys)
        if self._client_id is None or self._client_secret is None:
            config = self._load_config_file()
            if config:
                if self._client_id is None:
                    self._client_id = config.get("client_id")
                if self._client_secret is None:
                    self._client_secret = config.get("client_secret")

    @property
    def client_id(self) -> Optional[str]:
        """Get the client ID.

        Returns:
            The client ID if available, None otherwise
        """
        return self._client_id

    @property
    def client_secret(self) -> Optional[str]:
        """Get the client secret.

        Returns:
            The client secret if available, None otherwise
        """
        return self._client_secret

    def is_available(self) -> bool:
        """Check if both credentials are available.

        Returns:
            True if both client_id and client_secret are set, False otherwise
        """
        return self._client_id is not None and self._client_secret is not None

    def require(self) -> None:
        """Require that credentials are available, raising an error if not.

        Raises:
            GreenNodeConfigurationError: If credentials are not available

        Example:
            >>> creds = IAMCredentials()
            >>> creds.require()  # Raises if credentials not available
        """
        if not self.is_available():
            raise GreenNodeConfigurationError(
                "IAM credentials are required but not available. "
                "Please provide client_id and client_secret via constructor, "
                "environment variables (GREENNODE_CLIENT_ID, GREENNODE_CLIENT_SECRET), "
                "or config file (.greennode.json)."
            )

    @staticmethod
    def _load_config_file() -> Optional[dict]:
        """Load credentials from .greennode.json config file.

        Returns:
            Dictionary with client_id and client_secret if file exists and is valid, None otherwise
        """
        config_path = Path(".greennode.json")
        if not config_path.exists():
            return None

        try:
            with open(config_path, "r", encoding="utf-8") as file:
                config = json.load(file)
                if isinstance(config, dict):
                    return config
        except (json.JSONDecodeError, OSError):
            # Silently ignore config file errors
            pass

        return None
